import React, { useState } from 'react';
import { NavLink } from 'react-router-dom';
import './Header.css';
import './Header.responsive.css';

function Header() {
  const [menuOpen, setMenuOpen] = useState(false);

  const handleHamburgerClick = () => setMenuOpen(o => !o);
  const handleNavLinkClick = () => setMenuOpen(false);

  return (
    <header className="header">
      {/* Hamburger/list button always visible on mobile */}
      <button
        className={`hamburger${menuOpen ? ' close-x' : ''}`}
        aria-label={menuOpen ? 'Close navigation menu' : 'Open navigation menu'}
        aria-expanded={menuOpen}
        aria-controls="header-modal"
        onClick={handleHamburgerClick}
      >
        {menuOpen ? (
          <span style={{fontSize: '2.1rem', lineHeight: 1}}>&#10005;</span>
        ) : (
          <>
            <span />
            <span />
            <span />
          </>
        )}
      </button>

      {/* Modal-like overlay for mobile nav */}
      {menuOpen && (
        <div
          id="header-modal"
          className="header-modal-overlay"
          role="dialog"
          aria-modal="true"
        >
          <button
            className="modal-close-x"
            aria-label="Close navigation menu"
            onClick={handleHamburgerClick}
          >
            <span style={{fontSize: '2.1rem', lineHeight: 1}}>&#10005;</span>
          </button>
          <div className="header-modal-content">
            <h1>AI Quiz Builder</h1>
            <nav>
              <ul
                id="main-nav-list"
                className="nav-list open"
                onClick={handleNavLinkClick}
              >
                <li><NavLink to="/" end className={({isActive}) => isActive ? 'active' : ''}>Home</NavLink></li>
                <li><NavLink to="/create" className={({isActive}) => isActive ? 'active' : ''}>Create Quiz</NavLink></li>
                <li><NavLink to="/quizzes" className={({isActive}) => isActive ? 'active' : ''}>Predefined Quizzes</NavLink></li>
                <li><NavLink to="/india" className={({isActive}) => isActive ? 'active' : ''}>India Quizzes</NavLink></li>
                <li><NavLink to="/features" className={({isActive}) => isActive ? 'active' : ''}>Features</NavLink></li>
                <li><NavLink to="/about" className={({isActive}) => isActive ? 'active' : ''}>About</NavLink></li>
                <li><NavLink to="/contact" className={({isActive}) => isActive ? 'active' : ''}>Contact</NavLink></li>
              </ul>
            </nav>
          </div>
        </div>
      )}

      {/* Normal header content for desktop/tablet */}
      <div className="header-desktop">
        <h1>AI Quiz Builder</h1>
        <nav>
          <ul className="nav-list">
            <li><NavLink to="/" end className={({isActive}) => isActive ? 'active' : ''}>Home</NavLink></li>
            <li><NavLink to="/create" className={({isActive}) => isActive ? 'active' : ''}>Create Quiz</NavLink></li>
            <li><NavLink to="/quizzes" className={({isActive}) => isActive ? 'active' : ''}>Predefined Quizzes</NavLink></li>
            <li><NavLink to="/india" className={({isActive}) => isActive ? 'active' : ''}>India Quizzes</NavLink></li>
            <li><NavLink to="/features" className={({isActive}) => isActive ? 'active' : ''}>Features</NavLink></li>
            <li><NavLink to="/about" className={({isActive}) => isActive ? 'active' : ''}>About</NavLink></li>
            <li><NavLink to="/contact" className={({isActive}) => isActive ? 'active' : ''}>Contact</NavLink></li>
          </ul>
        </nav>
      </div>
    </header>
  );
}

export default Header;
